<?phpnamespace app\dep\Web;use app\dep\User\UsersDep;use app\model\Web\VisitorModel;use app\enum\CommonEnum;use Carbon\Carbon;class VisitorDep{    public $model;    public function __construct()    {        $this->model = new VisitorModel();    }    public function first($id)    {        $res = $this->model->where('id', $id)->first();        return $res;    }    public function firstByUserId($id)    {        $res = $this->model->where('user_id', $id)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByIp($ip)    {        $res = $this->model->where('ip', $ip)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstBySuperAdmin()    {        $res = $this->model->where('name', '超级管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByAdmin()    {        $res = $this->model->where('name', '管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }     public function firstByTitle($name)    {        $res = $this->model->where('title', $name)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function getUserByToken($token)    {        $res = $this->model->where('token', $token)->first();        return $res;    }    public function firstByEmail($email){        $res = $this->model->where('email',$email)->first();        return $res;    }    public function firstByToken($token){        $res = $this->model->where('token',$token)->first();        return $res;    }    public function all()    {        $res = $this->model->all();        return $res;    }    public function allOK()    {        $res = $this->model->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function add($data)    {        $res = $this->model->insertGetId($data);        return $res;    }    public function edit($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function batchEdit($ids, $data)    {        $res = $this->model->whereIn('id', $ids)->update($data);        return $res;    }    public function del($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function list($param){        $res = $this->model            ->where('is_del', CommonEnum::NO)            ->when(!empty($param['username']), function ($query) use ($param) {                if ($param['username'] === '游客') {                    // 如果输入的是"游客"，则直接过滤 user_id 为 -1 的记录                    $query->where('user_id', -1);                } else {                    $userDep = new UsersDep();                    $user_ids = $userDep->getByUsername($param['username'])->pluck('id');                    $query->whereIn('user_id', $user_ids);                }            })            ->when(!empty($param['ip']), function ($query) use ($param) {                $query->where('ip', 'like', '%' . $param['ip'] . '%');            })            ->when(!empty($param['time']) && is_array($param['time']), function ($query) use ($param) {                $query->whereBetween('created_at', [                    Carbon::parse($param['time'][0])->startOfDay(),                    Carbon::parse($param['time'][1])->endOfDay()                ]);            })            ->orderBy('created_at','desc')            ->paginate($param['page_size'], ['*'], 'page', $param['current_page']);        return $res;    }}